// 세 쿼리 결과 통합하여 LLM 프롬프트 구성
const stats    = $('이상 유형별 통계').all().map(i => i.json);
const top5     = $('Top5 시스템 조회').all().map(i => i.json);
const critical = $('미처리 Critical 조회').first().json;

const today = new Date().toLocaleDateString('ko-KR', {timeZone: 'Asia/Seoul'});

// 유형별 집계
const typeSummary = {};
stats.forEach(r => {
  typeSummary[r.anomaly_type] = (typeSummary[r.anomaly_type] || 0) + parseInt(r.cnt, 10);
});

const totalAlerts = Object.values(typeSummary).reduce((a, b) => a + b, 0);

const statsText = [
  `신규(new): ${typeSummary.new || 0}건`,
  `반복(recurring): ${typeSummary.recurring || 0}건`,
  `유사(related): ${typeSummary.related || 0}건`,
  `중복(duplicate): ${typeSummary.duplicate || 0}건`
].join(', ');

const top5Text = top5.map((r, i) =>
  `${i + 1}. ${r.display_name}(${r.system_name}): ${r.cnt}건`
).join('\n');

const prompt = `오늘(${today}) AOMS 모니터링 일일 리포트를 작성해 주세요.

[이상 탐지 통계]
- 총 알림: ${totalAlerts}건
- ${statsText}

[주요 발생 시스템 Top 5]
${top5Text || '없음'}

[미처리 Critical]: ${critical.unresolved_critical || 0}건

2~3문장으로 핵심 요약과 주의 사항을 작성해 주세요. 한국어로 답변하세요.`;

return [{
  json: { prompt, today, totalAlerts, typeSummary, top5, unresolvedCritical: critical.unresolved_critical || 0 }
}];

const llmResp  = $input.first().json;
const data     = $('리포트 데이터 통합').first().json;
const llmText  = llmResp.choices?.[0]?.message?.content || '요약 생성 실패';

const today = data.today;
const ts    = data.typeSummary;
const top5  = data.top5 || [];

const facts = [
  { title: '🆕 신규',  value: `${ts.new       || 0}건` },
  { title: '🔁 반복',  value: `${ts.recurring || 0}건` },
  { title: '🔗 유사',  value: `${ts.related   || 0}건` },
  { title: '🔄 중복',  value: `${ts.duplicate || 0}건` },
  { title: '⚠️ 미처리 Critical', value: `${data.unresolvedCritical}건` }
];

const top5Facts = top5.map((r, i) => ({
  title: `${i+1}위`,
  value: `${r.display_name}: ${r.cnt}건`
}));

return [{
  json: {
    type: 'message',
    attachments: [{
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          { type: 'TextBlock', text: `📊 AOMS 일일 이상 리포트 (${today})`, weight: 'Bolder', size: 'Large' },
          { type: 'TextBlock', text: '이상 분류 통계', weight: 'Bolder', size: 'Small', spacing: 'Medium' },
          { type: 'FactSet', facts },
          { type: 'TextBlock', text: '주요 발생 시스템 Top 5', weight: 'Bolder', size: 'Small', spacing: 'Medium' },
          { type: 'FactSet', facts: top5Facts.length ? top5Facts : [{ title: '-', value: '데이터 없음' }] },
          { type: 'TextBlock', text: '🤖 AI 요약', weight: 'Bolder', size: 'Small', spacing: 'Medium' },
          { type: 'TextBlock', text: llmText, wrap: true }
        ]
      }
    }]
  }
}];
